# OEIS sequence: A345176

def A345176(n):
    c, j = 0, 1
    while j <= n:
        k = n//j
        m = n//k
        c += k**j*(k**(m-j+1)-1)//(k-1) if k>1 else m-j+1
        j = m+1
    return c # _Chai Wah Wu_, May 14 2026

